  malphite: { diff: "EVEN", tone: "#e8b84b", tldr: "Bully his early \u2014 empowered W-stun, snowball.", breakdown: "Empowered W-stun + Q him early, out-trade his passive lane, and snowball before his R.", dos: ["Empowered W-stun all-in", "Out-trade his passive lane", "Snowball before he scales"], donts: ["Auto into his W", "Waste R-bait", "Let the game go late"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "Saved for fights. Lane is fine without it.", winT: "ULT DOWN", winS: "W-stun + Q him." }, hold: "Hold E\u2019s second dash to escape his W-empowered auto.", tip: "Empowered W-stun him early \u2014 his armor stacking is slow, so snowball before he comes online.", win: "Bully his early and snowball." },
  maokai: { diff: "EVEN", tone: "#e8b84b", tldr: "Bully him \u2014 dodge his root, snowball early.", breakdown: "Dodge his W root, empowered W-stun + Q him, and snowball before he scales.", dos: ["Dodge his W root", "Empowered W-stun all-in", "Snowball before he scales"], donts: ["Get rooted into his combo", "Fight in saplings", "Let the game go late"], key: { slot: "W", name: "Twisted Advance (Root)", cd: "11s", note: "His lock-on root. Dodge it.", winT: "ROOT DOWN", winS: "W-stun + Q him." }, hold: "Hold E\u2019s second dash to escape his root combo.", tip: "Empowered W-stun him before his root lands \u2014 your stun out-ranges his lock-on setup.", win: "Bully him early and dodge his root." },
