  ornn: { diff: "FAVOURED", tone: "#3ddc97", tldr: "Crush his early \u2014 dodge his Q, snowball.", breakdown: "Dodge his Q wall-knockups, empowered W-stun + Q him, and snowball before he scales.", dos: ["Dodge his Q + wall-knockups", "Empowered W-stun all-in", "Snowball before he scales"], donts: ["Stand near walls for his Q", "Get brittle-procced", "Let the game go late"], key: { slot: "Q", name: "Volcanic Rupture", cd: "10s", note: "Wall-knockup setup. Don\u2019t get pinned.", winT: "RUPTURE DOWN", winS: "W-stun + Q him." }, hold: "Hold E\u2019s second dash to escape his brittle combo.", tip: "Crush his weak early \u2014 empowered W-stun + Q him off CS before his tank scaling.", win: "Crush his early and snowball." },
  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Bully her \u2014 dodge her E, snowball early.", breakdown: "Dodge her E, empowered W-stun + Q her, and fight in open ground; watch her R.", dos: ["Dodge her E wall-stun", "Empowered W-stun all-in", "Fight in open ground"], donts: ["Get E-pinned on a wall", "Get R-knocked mid-burst", "Let the game go late"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Dodge it.", winT: "CHARGE DOWN", winS: "W-stun + Q her." }, hold: "Hold E\u2019s second dash to escape her E pin.", tip: "Note her W can block your E-dash \u2014 don\u2019t E-engage into an up Steadfast Presence.", win: "Bully her early and dodge her pin." },
