  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — fury-stun him on the Heroic Swing cooldown and dash out clean.","breakdown":"Akshan plays around Heroic Swing. Bank fury on the wave, slice in when Heroic Swing is down, empowered-W stun + Q heal, and dice out before he answers. Doran’s Shield blunts the poke war.","dos":["Build 50 fury before trading","E-W-Q burst when Heroic Swing is down","Dash out before his answer"],"donts":["Trade at zero fury","Eat his Heroic Swing for free","Overstay after the burst"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Fury W-stun + dash out."},"win":"Fury-stun him on the Heroic Swing cooldown and dash out clean."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then fury-stun him on the Miasma cooldown and dash out clean.","breakdown":"Cassiopeia plays around Miasma. Bank fury on the wave, slice in when Miasma is down, empowered-W stun + Q heal, and dice out before he answers. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Build 50 fury before trading","E-W-Q burst when Miasma is down","Dash out before his answer"],"donts":["Trade at zero fury","Eat his Miasma for free","Overstay after the burst"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Fury W-stun + dash out."},"win":"Fury-stun him on the Miasma cooldown and dash out clean."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — fury-stun him on the Justice Punch cooldown and dash out clean.","breakdown":"Galio plays around Justice Punch. Bank fury on the wave, slice in when Justice Punch is down, empowered-W stun + Q heal, and dice out before he answers. Take Mercs / MR shard — his damage is magic.","dos":["Build 50 fury before trading","E-W-Q burst when Justice Punch is down","Dash out before his answer"],"donts":["Trade at zero fury","Eat his Justice Punch for free","Overstay after the burst"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"Fury W-stun + dash out."},"win":"Fury-stun him on the Justice Punch cooldown and dash out clean."},
